mapper.select:
SELECT COALESCE(MAX(sort_order), 0) + 1
FROM agent_conversation_folder
WHERE user_id = #{userId}

mapper.update:
UPDATE agent_conversation_folder
SET name = #{name},
    sort_order = #{sortOrder},
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM agent_conversation_folder
WHERE id = #{id}
  AND user_id = #{userId}
